#include <bits/stdc++.h>
using namespace std;
const int N=1e5+5;
struct Node{
	int val,id;
};
bool operator<(Node x,Node y){
	return x.val<y.val;
}
int n,a[N],f[N][2],ans;
bool b[N];
vector<int> g[N];
void dfs(int x){
	b[x]=1;
	int len=g[x].size();
	priority_queue<Node> s[2]; 
	f[x][a[x]]=0;
	for(int i=0;i<len;i++)
		if(!b[g[x][i]]){
			dfs(g[x][i]);
			if(f[g[x][i]][0]>=0)
				s[0].push({f[g[x][i]][0]+1,g[x][i]});
			if(f[g[x][i]][1]>=0)
				s[1].push({f[g[x][i]][1]+1,g[x][i]});
			f[x][0]=max(f[x][0],f[g[x][i]][0]+1);
			f[x][1]=max(f[x][1],f[g[x][i]][1]+1);
		}
	if(s[0].size() && s[1].size() && s[0].top().id!=s[1].top().id)
		ans=max(ans,s[0].top().val+s[1].top().val);
	else if(s[0].size() && s[1].size()){
		Node a=s[0].top(),b=s[1].top();
		s[0].pop(),s[1].pop();
		if(s[0].size())
			ans=max(ans,s[0].top().val+b.val);
		if(s[1].size())
			ans=max(ans,a.val+s[1].top().val);
	}
	ans=max(ans,f[x][a[x]^1]);
}
int main(){
	memset(f,-127,sizeof(f));
	scanf("%d",&n);
	for(int i=1;i<=n;i++)
		scanf("%d",&a[i]);
	for(int i=1;i<n;i++){
		int u,v;
		scanf("%d%d",&u,&v);
		g[u].push_back(v);
		g[v].push_back(u);
	}
	dfs(1);
	printf("%d",ans);
	return 0;
}
